import{c as a,Q as t,j as i,m as r}from"./chunks/framework.BXc4yaFE.js";const g=JSON.parse('{"title":"Closing the Verification Loop: Observability-Driven Harnesses for Building with Agents","description":"","frontmatter":{"url":"https://www.datadoghq.com/blog/ai/harness-first-agents/","date":"2026-03-09T00:00:00.000Z","authors":"Datadog Engineering","source":"Datadog AI Blog","tags":["harness-first","verification","formal-methods","observability","DST"]},"headers":[],"relativePath":"research/ai-articles/scored/2026-03-09-datadog-harness-first-verification-loop.md","filePath":"research/ai-articles/scored/2026-03-09-datadog-harness-first-verification-loop.md","lastUpdated":1779894392000}'),s={name:"research/ai-articles/scored/2026-03-09-datadog-harness-first-verification-loop.md"};function n(o,e,l,d,c,h){return t(),i("div",null,[...e[0]||(e[0]=[r(`<h1 id="closing-the-verification-loop-observability-driven-harnesses-for-building-with-agents" tabindex="-1">Closing the Verification Loop: Observability-Driven Harnesses for Building with Agents <a class="header-anchor" href="#closing-the-verification-loop-observability-driven-harnesses-for-building-with-agents" aria-label="Permalink to &quot;Closing the Verification Loop: Observability-Driven Harnesses for Building with Agents&quot;">​</a></h1><p><strong>原始來源</strong>：<a href="https://www.datadoghq.com/blog/ai/harness-first-agents/" target="_blank" rel="noreferrer">https://www.datadoghq.com/blog/ai/harness-first-agents/</a><br><strong>作者</strong>：Datadog Engineering<br><strong>歸檔日期</strong>：2026-05-10</p><hr><h2 id="評分摘要" tabindex="-1">評分摘要 <a class="header-anchor" href="#評分摘要" aria-label="Permalink to &quot;評分摘要&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>理由</th></tr></thead><tbody><tr><td>A. Workspace 可行動性</td><td>9/10</td><td>具體 verification pyramid 可直接套用</td></tr><tr><td>B. 創新性</td><td>8/10</td><td>Harness-first 反轉傳統 code review 是新思維</td></tr><tr><td>C. 證據品質</td><td>9/10</td><td>生產案例含具體數字（87% memory reduction, 10M simulations）</td></tr><tr><td>D. 技術深度</td><td>9/10</td><td>TLA+ specs + DST + model checking + telemetry 四層詳解</td></tr><tr><td>E. 泛化性</td><td>8/10</td><td>適用任何有 simulated 環境的系統</td></tr><tr><td><strong>加權總分</strong></td><td><strong>8.6/10</strong></td><td>9×0.3 + 8×0.2 + 9×0.2 + 9×0.15 + 8×0.15 = 8.60</td></tr></tbody></table><p><strong>整合決策</strong>：RULE — 核心原則（Verification Loop 作為 harness 設計要求）<br><strong>整合位置</strong>：<code>research/agent-harness/FRAMEWORK.md</code> §驗證策略<br><strong>整合狀態</strong>：待實作</p><hr><h2 id="tl-dr" tabindex="-1">TL;DR <a class="header-anchor" href="#tl-dr" aria-label="Permalink to &quot;TL;DR&quot;">​</a></h2><p>Harness-first 方法論：automated verification 取代 line-by-line code review。實作 Verification Pyramid（TLA+ → DST → model checking → production telemetry）。人類角色從「審查程式碼」轉為「定義不變量」。生產案例：redis-rust 優化（87% memory reduction）、Helix Kafka 語意（93% throughput across 10M simulations）。</p><hr><h2 id="核心主張" tabindex="-1">核心主張 <a class="header-anchor" href="#核心主張" aria-label="Permalink to &quot;核心主張&quot;">​</a></h2><h3 id="_1-harness-first-思維反轉" tabindex="-1">1. Harness-First 思維反轉 <a class="header-anchor" href="#_1-harness-first-思維反轉" aria-label="Permalink to &quot;1. Harness-First 思維反轉&quot;">​</a></h3><p><strong>舊模式</strong>：寫程式碼 → code review → 測試 → 部署<br><strong>新模式</strong>：定義不變量（invariants）→ 建 harness → 讓 agent 在 harness 約束下工作</p><blockquote><p>&quot;We don&#39;t review AI-generated code line by line; we verify it against formally specified invariants.&quot;</p></blockquote><h3 id="_2-verification-pyramid-四層" tabindex="-1">2. Verification Pyramid（四層） <a class="header-anchor" href="#_2-verification-pyramid-四層" aria-label="Permalink to &quot;2. Verification Pyramid（四層）&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>TLA+ Specifications（最高層）</span></span>
<span class="line"><span>         ↓</span></span>
<span class="line"><span>Deterministic Simulation Testing（DST）</span></span>
<span class="line"><span>         ↓  </span></span>
<span class="line"><span>Model Checking</span></span>
<span class="line"><span>         ↓</span></span>
<span class="line"><span>Production Telemetry（最低層）</span></span></code></pre></div><h3 id="_3-生產案例數據" tabindex="-1">3. 生產案例數據 <a class="header-anchor" href="#_3-生產案例數據" aria-label="Permalink to &quot;3. 生產案例數據&quot;">​</a></h3><p><strong>redis-rust 優化</strong>：</p><ul><li>AI 生成優化建議 → DST 驗證 → 87% memory reduction</li><li>等效生產延遲：通過 DST 確認</li><li>Code review 時間：0 小時（replaced by DST）</li></ul><p><strong>Helix Kafka 語意</strong>：</p><ul><li>10M simulations across 5 failure modes</li><li>93% throughput maintain across all scenarios</li><li>人工測試等效工時：~120 天 → DST：3 小時</li></ul><hr><h2 id="對-cc-workspace-的直接意涵" tabindex="-1">對 cc-workspace 的直接意涵 <a class="header-anchor" href="#對-cc-workspace-的直接意涵" aria-label="Permalink to &quot;對 cc-workspace 的直接意涵&quot;">​</a></h2><h3 id="_1-deep-review-升級方向" tabindex="-1">1. <code>/deep-review</code> 升級方向 <a class="header-anchor" href="#_1-deep-review-升級方向" aria-label="Permalink to &quot;1. \`/deep-review\` 升級方向&quot;">​</a></h3><p>目前 <code>/deep-review</code> 以 LLM 審查為主（Generator ≠ Evaluator 原則）。<br> Datadog 的 harness-first 建議加入<strong>確定性驗證</strong>：</p><ul><li>現有 <code>bash scripts/healthcheck.sh</code> = 初級 invariant check</li><li>可擴充：在 <code>/deep-review</code> 的 Execution Checklist 加入 deterministic test 步驟</li></ul><h3 id="_2-known-gotchas-從「事後記錄」到「事前-invariant」" tabindex="-1">2. Known Gotchas 從「事後記錄」到「事前 invariant」 <a class="header-anchor" href="#_2-known-gotchas-從「事後記錄」到「事前-invariant」" aria-label="Permalink to &quot;2. Known Gotchas 從「事後記錄」到「事前 invariant」&quot;">​</a></h3><p>Ratchet 原則的進化：</p><ul><li><strong>現有</strong>：踩坑 → 記入 Known Gotchas → rule 升格</li><li><strong>目標</strong>：預先定義不變量 → harness 防止踩坑 → 無需事後記錄</li></ul><h3 id="_3-observability-作為-harness-設計要求" tabindex="-1">3. Observability 作為 harness 設計要求 <a class="header-anchor" href="#_3-observability-作為-harness-設計要求" aria-label="Permalink to &quot;3. Observability 作為 harness 設計要求&quot;">​</a></h3><p>AHE (2604.25850) 研究同樣強調 observability。Datadog 從工業界確認：</p><ul><li>無可觀測性的 harness = 黑箱（無法改善）</li><li>telemetry 是 verification loop 的最後防線</li></ul><hr><h2 id="升級路徑建議" tabindex="-1">升級路徑建議 <a class="header-anchor" href="#升級路徑建議" aria-label="Permalink to &quot;升級路徑建議&quot;">​</a></h2><ol><li><strong>短期</strong>：在 <code>healthcheck.sh</code> 加入一個 invariant check（例：<code>.claude/rules/</code> 中的所有 @import 均存在）</li><li><strong>中期</strong>：在 <code>/deep-review</code> 加入 deterministic test phase（lint + type check + unit test 作為 hard gate）</li><li><strong>長期</strong>：研究 DST 是否適用於 CLAUDE.md rule 變更的回歸驗證</li></ol>`,35)])])}const u=a(s,[["render",n]]);export{g as __pageData,u as default};
